import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    const name = (
        <div>
            <head>
                <title>React Sucks!</title>
            </head>
            <body>
                <h3>Hello React!</h3>
                <h3>The time is: {new Date().toLocaleTimeString()}.</h3>
            </body>
        </div>
    );
    ReactDOM.render(name, document.getElementbyId('root'))
}
homePage();
